    package_data = json.load(f)

# Parse package data to find latest releases
from collections import defaultdict
import re

latest_packages = {}

for pkg in package_data:
    if pkg['System'] == 'NPM':
        try:
            # Parse VersionInfo JSON
            version_info_str = pkg['VersionInfo'].replace('\n', '').strip()
            version_info = json.loads(version_info_str)

            if version_info.get('IsRelease'):
                name = pkg['Name']
                ordinal = version_info.get('Ordinal', 0)

                # Keep only the highest ordinal for each package
                if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
                    latest_packages[name] = {
                        'name': name,
                        'version': pkg['Version'],
                        'ordinal': ordinal,
                        'published_at': pkg.get('UpstreamPublishedAt')
                    }
        except Exception as e:
            # Skip malformed entries
            continue

print("__RESULT__:")
print(json.dumps({
    "total_latest_packages": len(latest_packages),
    "sample_packages": list(latest_packages.values())[:5]
}))

